char_vect = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 !?.,/<>-+=[]@$#"~abcdefghijklmnopqrstuvwxyz'

text.set(text.LatexEngine)
text.preamble(r"\usepackage{helvet}\renewcommand{\familydefault}{\sfdefault}")

c = canvas.canvas()

B = 2.4
G = 0.1
ROWS, COLS = (11, 8)

p = path.rect(-.3, -.1, COLS*(B+G) + .4, ROWS*(B+G) + 0.2)
c.stroke(p, [style.linewidth.Thin, style.linestyle.dashed])

now = datetime.datetime.now()
d = str(now).split('.')[0]
c.text(0, 0, d, [color.rgb.red])

for i,g in enumerate(gest):
    offs_x = (i % COLS) * (B+G)
    offs_y = 24 - (i // COLS) * (B+G)
    p = path.rect(offs_x, offs_y, B, B)
    c.stroke(p, [style.linewidth.Thick])
    C = char_vect[i]
    if C in ['$','#']:
        C = f'\\{C}'
    elif C == '<':
        C = '$<$'
    elif C == '>':
        C = '$>$'
    elif C == '[':
        C = '$[$'
    elif C == ']':
        C = '$[$'
    elif C == ' ':
        C = '$<$space$>$'
    elif C == '"':
        C = "''"
    elif C == '~':
        C = "$\\sim$"
    elif C == '.':
        C = '$<$dot$>$'
    elif C == ',':
        C = '$<$comma$>$'
    # print("--", C, "--")
    c.text(offs_x+0.2, offs_y+0.2, C, [color.rgb.red])

    def scale(v):
        t = (offs_x + B * v[0]/(10*256/8), offs_y + B * v[1]/(10*256/8))
        return t

    pt = scale(g[0])
    pts = path.path( path.moveto(pt[0], pt[1]) )
    seg = g[0][2]
    for pt in g[1:]:
        pt2 = scale(pt)
        if pt[2] == seg:
            pts.append( path.lineto(pt2[0], pt2[1]) )
        else:
            seg = pt[2]
            pts.append( path.moveto(pt2[0], pt2[1]) )
    c.stroke(pts, [style.linewidth.Thick])
        
pg = document.page(c, paperformat=document.paperformat.A4)
d = document.document([pg])
d.writePDFfile("gallery")

print(f"#define PROTOTYPES_CNT {len(char_vect)}")
print("static const PROGMEM struct gest_s prototypes[PROTOTYPES_CNT] = {")
for i,g in enumerate(gest):
    print("  { .pts = {", end='')
    for j,t in enumerate(g):
        if j != 0:
            print(",", end='')
        print("to_pt", end='')
        print(str(t).replace(' ', ''), end='')
    print("},");
    print(f"    .name='{char_vect[i]}'", end="},\n")
print("};")

